// All 13 GDA target departments mapped to SAM.gov organization search terms
// SAM API uses 'organizationId' but keyword search on department name is more reliable
const departments = [
  { dept: 'Department of War', sam_query: 'DEPT OF DEFENSE', subtier_keywords: ['army','navy','air force','marine','socom','disa','darpa','mda','dla','dtra','nsa','dia','nga','nro'] },
  { dept: 'Department of Homeland Security', sam_query: 'DEPT OF HOMELAND SECURITY', subtier_keywords: ['cbp','ice','tsa','fema','coast guard','cisa','secret service'] },
  { dept: 'Intelligence Community', sam_query: 'CENTRAL INTELLIGENCE AGENCY', subtier_keywords: ['cia','dni','odni'] },
  { dept: 'Department of Veterans Affairs', sam_query: 'DEPT OF VETERANS AFFAIRS', subtier_keywords: ['vha','vba'] },
  { dept: 'Department of Energy', sam_query: 'DEPT OF ENERGY', subtier_keywords: ['nnsa','doe'] },
  { dept: 'NASA', sam_query: 'NATIONAL AERONAUTICS AND SPACE ADMINISTRATION', subtier_keywords: ['nasa'] },
  { dept: 'Department of Justice', sam_query: 'DEPT OF JUSTICE', subtier_keywords: ['fbi','dea','atf','marshals'] },
  { dept: 'Department of State', sam_query: 'DEPT OF STATE', subtier_keywords: [] },
  { dept: 'Department of Commerce', sam_query: 'DEPT OF COMMERCE', subtier_keywords: ['noaa','nist','census'] },
  { dept: 'Department of Health and Human Services', sam_query: 'DEPT OF HEALTH AND HUMAN SERVICES', subtier_keywords: ['cdc','nih','cms','fda'] },
  { dept: 'Department of the Interior', sam_query: 'DEPT OF THE INTERIOR', subtier_keywords: ['blm','usgs','nps'] },
  { dept: 'Department of Transportation', sam_query: 'DEPT OF TRANSPORTATION', subtier_keywords: ['faa','fhwa','fra'] },
  { dept: 'General Services Administration', sam_query: 'GENERAL SERVICES ADMINISTRATION', subtier_keywords: ['gsa','fas','pbs'] }
];
return departments.map(function(d) { return { json: d }; });

const allItems = $input.all();
const results = [];
const seen = new Set();
const EIS_KEYWORDS = /seta|training|simulat|cyber|intel|c5isr|sigint|it support|cloud|network|engineer|software|consult|analyst|logist|ai |machine learning|data|sensor|command|control|missile|defense|shield/i;

for (const item of allItems) {
  if (item.json.error) continue;
  const opps = item.json.opportunitiesData || [];
  for (const opp of opps) {
    const id = opp.solicitationNumber || opp.noticeId || '';
    if (!id || seen.has(id)) continue;
    const title = (opp.title || '').toLowerCase();
    // Pre-filter: skip obviously irrelevant (construction, janitorial, food, etc)
    if (/janitorial|custodial|food service|laundry|grounds|mowing|plumbing|hvac|roofing|paving|demolition/.test(title)) continue;
    seen.add(id);
    const hier = opp.organizationHierarchy || [];
    const agency = hier.length > 0 ? hier[0].name : (opp.fullParentPathName || opp.organizationName || '');
    const subtier = hier.length > 1 ? hier[1].name : '';
    results.push({ json: {
      solicitation_number: id.substring(0, 255),
      name: agency.substring(0, 500),
      title: (opp.title || '').substring(0, 500),
      opp_title: (opp.title || '').substring(0, 500),
      opportunity_type: opp.type || '',
      set_aside: opp.typeOfSetAsideDescription || opp.typeOfSetAside || '',
      posted_date: opp.postedDate || null,
      due_date: opp.responseDeadLine || opp.archiveDate || null,
      response_deadline: opp.responseDeadLine || opp.archiveDate || null,
      agency: agency.substring(0, 500),
      dept: hier.length > 0 ? hier[0].name : 'Unknown',
      level_2: subtier,
      naics_code: (opp.naicsCode || '').substring(0, 20),
      source_url: opp.uiLink || ('https://sam.gov/opp/' + (opp.noticeId || '') + '/view'),
      data_source: 'SAM.gov Dept Sweep',
      govtribe_id: opp.noticeId || '',
      description: (opp.description || '').substring(0, 2000),
      place_of_performance: (opp.placeOfPerformance || {}).state || '',
      estimated_value: 0,
      _hasData: true
    }});
  }
}
if (results.length === 0) return [{ json: { _hasData: false, _fetched: 0, _msg: 'No new opps from dept sweep' } }];
return results;

const items = $input.all();
if (items[0]?.json?._hasData === false) return items;
const EIS_NAICS = ['541330','541511','541512','541513','541519','541611','541690','541715','541990','611430','561210','561110'];
const TARGET_AGENCIES = ['socom','tradoc','peo stri','inscom','cybercom','disa','indopacom','mda','missile defense','faa'];
function calc(o){
  let s=0;
  const t=((o.opp_title||o.title||'')+(o.description||'')).toLowerCase();
  const n=o.naics_code||'';
  const sa=(o.set_aside||'').toLowerCase();
  const ag=(o.agency||'').toLowerCase();
  const dl=o.due_date?Math.ceil((new Date(o.due_date)-new Date())/864e5):90;
  s+=EIS_NAICS.includes(n)?15:n.startsWith('5415')?8:n.startsWith('541')?5:0;
  let mp=0;
  if(/seta|systems engineering/.test(t))mp=15;
  if(/simulat|training|virtual/.test(t))mp=Math.max(mp,12);
  if(/missile|defense|shield|golden dome/.test(t))mp=Math.max(mp,12);
  if(/cyber|c5isr/.test(t))mp=Math.max(mp,10);
  if(/intel|intelligence|sigint/.test(t))mp=Math.max(mp,10);
  if(/air traffic|atc|faa/.test(t))mp=Math.max(mp,8);
  if(/it support|cloud|network/.test(t))mp=Math.max(mp,8);
  s+=Math.min(mp,15);
  if(/seta|training|simulat|peo stri|tradoc/.test(t))s+=10;
  else if(/cyber|protect|security|disa/.test(t))s+=10;
  else if(/software|engineer|develop/.test(t))s+=10;
  else if(/socom|inscom|army|navy/.test(t))s+=7;
  else s+=5;
  if(/sdvosb|service.disabled/.test(sa))s+=10;
  else if(/8\(a\)|8a/.test(sa))s+=10;
  else if(/hubzone/.test(sa))s+=9;
  else if(/small business/.test(sa)&&!/no set/.test(sa))s+=8;
  else s+=3;
  let pp=2;
  for(const ta of TARGET_AGENCIES){if(ag.includes(ta)){pp=15;break;}}
  if(pp<15&&/army|war/.test(ag))pp=10;
  if(pp<10&&/navy|air force|defense/.test(ag))pp=7;
  s+=pp;
  s+=/sole.source|limited/.test(sa+t)?10:/small business/.test(sa)?7:3;
  s+=3; // no value data from SAM search
  if(/iews|recompete/.test(t))s+=10;
  else if(/shield|mda/.test(t))s+=8;
  else if(/idiq|task order/.test(t))s+=6;
  else s+=2;
  s+=dl>45?5:dl>30?4:dl>14?2:1;
  return Math.min(Math.max(Math.round(s),0),100);
}
return items.map(function(i){
  const o=i.json;
  if(!o._hasData && o._hasData !== undefined) return i;
  const gs=calc(o);
  return {json:{...o, gda_score:gs, gda_label:gs>=80?'PURSUE':gs>=60?'EVALUATE':gs>=40?'MONITOR':'PASS', eis_fit_score:gs}};
});

const items = $input.all();
const isNoData = items[0]?.json?._hasData === false;
const summary = {
  timestamp: new Date().toISOString(),
  workflow: 'GDA.sched.dept-opp-sweep',
  departments_searched: 13,
  opps_found: isNoData ? 0 : items.length,
  status: isNoData ? 'no_new_data' : 'ok'
};
console.log('[DEPT SWEEP]', JSON.stringify(summary));
return [{ json: summary }];
